      line-height: 14px;
    }

    .AppCore-badge__icon ::ng-deep .material-symbols-rounded,
    .AppCore-badge__icon ::ng-deep img.icon {
      font-size: 12px !important;
      width: 12px !important;
      height: 12px !important;
    }
  }

  &--size-M {
    padding: 4px 8px;

    .AppCore-badge__label {
      font-size: 12px;
      line-height: 16px;
    }

    .AppCore-badge__icon ::ng-deep .material-symbols-rounded,
    .AppCore-badge__icon ::ng-deep img.icon {
      font-size: 14px !important;
      width: 14px !important;
      height: 14px !important;
    }
  }

  &--size-L {
    padding: 5px 10px;

    .AppCore-badge__label {
      font-size: 14px;
      line-height: 18px;
    }

    .AppCore-badge__icon ::ng-deep .material-symbols-rounded,
    .AppCore-badge__icon ::ng-deep img.icon {
      font-size: 16px !important;
      width: 16px !important;
      height: 16px !important;
    }
  }

  // ===== Default Type =====
  &--type-Default {
    &.AppCore-badge--style-Outlined {
      background-color: $color-tokens-surface-neutral-white;
      border-color: $color-tokens-border-neutral-light-stroke-divider;
      color: $color-tokens-content-neutral-heading2-label2-body1;
    }

    &.AppCore-badge--style-Toned {
      background-color: $color-tokens-surface-neutral-white-faded;
      border-color: transparent;
      color: $color-tokens-content-neutral-heading2-label2-body1;
    }

    &.AppCore-badge--style-Highlighted {
      background-color: $color-tokens-surface-neutral-black-default;
      border-color: transparent;
      color: $color-tokens-content-neutral-button-darkbg;
    }
  }

  // ===== Error Type =====
  &--type-Error {
    &.AppCore-badge--style-Outlined {
      background-color: $color-tokens-surface-neutral-white;
      border-color: $color-tokens-surface-error-hover; // error-75 shade, no error-border-light token in project
      color: $color-tokens-content-error-default;
    }

    &.AppCore-badge--style-Toned {
      background-color: $color-tokens-surface-error-background-light;
      border-color: transparent;
      color: $color-tokens-content-error-default;
    }

    &.AppCore-badge--style-Highlighted {
      background-color: $color-tokens-surface-error-default;
      border-color: transparent;
      color: $color-tokens-content-neutral-button-darkbg;
    }
  }

  // ===== Success Type =====
  &--type-Success {
    &.AppCore-badge--style-Outlined {
      background-color: $color-tokens-surface-neutral-white;
      border-color: $color-tokens-border-success-light;
      color: $color-tokens-content-success-default;
    }

    &.AppCore-badge--style-Toned {
      background-color: $color-tokens-surface-success-background-light;
      border-color: transparent;
      color: $color-tokens-content-success-default;
    }

    &.AppCore-badge--style-Highlighted {
      background-color: $color-tokens-surface-success-default;
      border-color: transparent;
      color: $color-tokens-content-neutral-button-darkbg;
    }
  }

  // ===== Warning Type =====
  &--type-Warning {
    &.AppCore-badge--style-Outlined {
      background-color: $color-tokens-surface-neutral-white;
      border-color: $color-tokens-border-warning-light;
      color: $color-tokens-content-warning-default;
    }

    &.AppCore-badge--style-Toned {
      background-color: $color-tokens-surface-warning-background-dark;
      border-color: transparent;
      color: $color-tokens-content-neutral-display-heading1-label1-selected;
    }

    &.AppCore-badge--style-Highlighted {
      background-color: $color-tokens-surface-warning-default;
      border-color: transparent;
      color: $color-tokens-content-neutral-display-heading1-label1-selected;
    }
  }

  // ===== Information Type =====
  &--type-Information {
    &.AppCore-badge--style-Outlined {
      background-color: $color-tokens-surface-neutral-white;
      border-color: $color-tokens-border-primary-default;
      color: $color-tokens-content-primary-default;
    }

    &.AppCore-badge--style-Toned {
      background-color: $color-tokens-surface-primary-background-light;
      border-color: transparent;
      color: $color-tokens-content-primary-default;
    }

    &.AppCore-badge--style-Highlighted {
      background-color: $color-tokens-surface-primary-default;
      border-color: transparent;
      color: $color-tokens-content-neutral-button-darkbg;
    }
  }

  // Icon inherits text color
  &__icon ::ng-deep .material-symbols-rounded,
  &__icon ::ng-deep img.icon {
    color: inherit !important;
  }

  &__label {
    display: inline;
    font-family: inherit;
    font-weight: inherit;
    color: inherit;
  }
}

