@use '../../styles/primitives' as *;
@use '../../styles/numbers' as *;
@use '../../styles/typography' as *;
@use '../../styles/colors' as *;

.AppCore-badge-indicator {
  display: inline-flex;
  align-items: center;
  gap: 4px;

  // ===== Dot - Inline (default layout: flex row) =====
  &--style-dot-inline {
    // inherits default inline-flex + gap
  }

  // ===== Dot - Overlapping =====
  &--style-dot-overlapping {
    position: relative;
    width: 24px;
    height: 24px;
    gap: 0;

    .AppCore-badge-indicator__dot {
      position: absolute;
      top: 0;
      right: 0;
      z-index: 1;
    }
  }

  // ===== With Text (standalone pill, no avatar) =====
  &--style-text {
    gap: 0;
  }

  // ===== With Text - Overlapping =====
  &--style-text-overlapping {
    position: relative;
    width: 28px;
    height: 28px;
    gap: 0;

    .AppCore-badge-indicator__avatar {
      position: absolute;
      top: 2px;
      left: 2px;
    }

    .AppCore-badge-indicator__pill {
      position: absolute;
      top: 0;
      left: 14px;
    }
  }

  // ===== Dot =====
  &__dot {
    width: 8px;
    height: 8px;
    border-radius: 40px;
    flex-shrink: 0;
  }

  // ===== Avatar placeholder =====
  &__avatar {
    font-size: 24px !important;
    width: 24px !important;
    height: 24px !important;
    color: $color-tokens-content-neutral-disabled;
    flex-shrink: 0;
