@if (src) {
  <img
    class="icon"
    [ngClass]="[size, color ?? 'default', background ?? 'default']"
    [src]="src"
    [alt]="alt || icon || 'icon'"
  />
} @else if (iconSet === 'material') {
  <span
    class="material-symbols-rounded icon"
    [ngClass]="[size, color ?? 'default', background ?? 'default']"
    [attr.aria-label]="alt || materialIconName"
  >{{ materialIconName }}</span>
} @else if (icon) {
  <img
    class="icon"
    [ngClass]="[size, color ?? 'default', background ?? 'default']"
    [src]="'assets/icons/' + icon + '.svg'"
    [alt]="alt || icon"
  />
}

components.sourceCode:
import { Component, Input } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-icon',
  standalone: true,
  imports: [CommonModule],
  template: `
    @if (src) {
      <img
        class="icon"
        [ngClass]="[size, color ?? 'default', background ?? 'default']"
        [src]="src"
        [alt]="alt || icon || 'icon'"
      />
    } @else if (iconSet === 'material') {
      <span
        class="material-symbols-rounded icon"
        [ngClass]="[size, color ?? 'default', background ?? 'default']"
        [attr.aria-label]="alt || materialIconName"
      >{{ materialIconName }}</span>
    } @else if (icon) {
      <img
        class="icon"
        [ngClass]="[size, color ?? 'default', background ?? 'default']"
        [src]="'assets/icons/' + icon + '.svg'"
        [alt]="alt || icon"
      />
    }
  `,
  styleUrls: ['./icon.scss'],
})
export class IconComponent {
  /** Icon name: for Material use names like "add", "search", "arrow_forward"; for asset use file name without .svg (e.g. "icon-search"). */
  @Input() icon!: string;
  /**
   * Custom icon URL. When set, this is used as the img src and icon/iconSet are ignored.
   * Use for fully custom icons passed from outside (e.g. CDN, data URL, or app asset path).
   */
  @Input() src?: string;
  /**
   * 'material' = Material Symbols Rounded (default); 'asset' = SVG from assets/icons/
   * When using iconSet="material", the host app must load the font, e.g. in index.html:
   * <link href="https://fonts.googleapis.com/css2?family=Material+Symbols+Rounded:opsz,wght,FILL,GRAD@20..48,100..700,0..1,-50..200" rel="stylesheet">
   */
  @Input() iconSet: 'material' | 'asset' = 'material';
  @Input() size: 'sm' | 'md' | 'lg' = 'md';
  @Input() alt?: string;
  @Input() color?: 'primary' | 'neutral' | 'default' = 'default';
  @Input() background?: 'primary' | 'neutral' | 'default' = 'default';

  /** Material Symbol name: strip "icon-" prefix so "icon-add" and "add" both work */
  get materialIconName(): string {
    return this.icon?.replace(/^icon-/, '') ?? '';
  }
}

styleUrlsData.data:
@use '../../styles/primitives' as *;
@use '../../styles/numbers' as *;
@use '../../styles/typography' as *;
@use '../../styles/colors' as *;
@use 'sass:map';

/* Shared icon wrapper (img or Material Symbol span) */
.icon {
  width: 1rem;
  height: 1rem;
  display: inline-flex;
  align-items: center;
  justify-content: center;

  &.sm {
    width: 0.75rem;
    height: 0.75rem;
  }

  &.md {
    width: 1rem;
    height: 1rem;
  }

  &.lg {
    width: 1.5rem;
    height: 1.5rem;
  }

  &.primary {
    color: $color-tokens-content-primary-default;
  }

  &.neutral {
    color: $color-tokens-content-neutral-body2;
  }

  &.default {
    color: $color-tokens-content-neutral-heading2-label2-body1;
  }
}

/* Material Symbols Rounded (font-based) – size via font-size */
.icon.material-symbols-rounded {
  font-family: 'Material Symbols Rounded', sans-serif !important;
  font-weight: normal;
  font-style: normal;
  font-variation-settings: 'FILL' 0, 'wght' 400, 'GRAD' 0, 'opsz' 24;
  line-height: 1;
  letter-spacing: normal;
  text-transform: none;
  white-space: nowrap;
  word-wrap: normal;
  direction: ltr;
  -webkit-font-smoothing: antialiased;

  &.sm {
    font-size: 0.75rem !important;
    width: 0.75rem;
    height: 0.75rem;
  }

  &.md {
    font-size: 1rem !important;
    width: 1rem;
    height: 1rem;
  }

  &.lg {
    font-size: 1.5rem !important;
    width: 1.5rem;
    height: 1.5rem;
  }
}

